Rule.Source:
  import sailpoint.api.ObjectUtil;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;  
  import sailpoint.object.Identity;
  import sailpoint.object.Link;   
  import sailpoint.tools.Util;
  import sailpoint.tools.GeneralException;
  import sailpoint.api.SailPointContext; 
  import sailpoint.api.Workflower;
  import sailpoint.object.ProvisioningProject;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.api.Provisioner;
  import java.util.Map;
  import java.util.HashMap;
  import java.util.List;
  import java.util.ArrayList;
  import java.util.Iterator;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Custom;
  import sailpoint.object.Attributes;

  Iterator linksDelIterator=null;

  List usersList=new ArrayList();
  
  Identity identity=null;
  List linksAccount=new ArrayList();
  String applicationName = "DB-Peoplesoft-HCM-Primary";
  Custom userObject = context.getObject(Custom.class,"Ascension-Custom-ILARL-CWR-Users");
  if(userObject != null){
    Attributes attr = userObject.getAttributes();
    if(attr != null){
      Map objectMap = attr.getMap();
      if(objectMap != null){
        usersList = objectMap.get("ILARLCWRUsers");

      }
    }
  }


  List test=new ArrayList();
  if(usersList!=null && !usersList.isEmpty()){
    for(String strname:usersList){

      QueryOptions qryOpt=new QueryOptions();
      Filter f1=Filter.or(Filter.eq("name",strname),Filter.eq("employeeId",strname));
      qryOpt.addFilter(f1);
      Iterator iterator = context.search(Identity.class,qryOpt);  

      if(iterator != null && iterator.hasNext()){
        Identity identity = iterator.next();
        List users=new ArrayList();
        String applicationName = "DB-Peoplesoft-HCM-Primary";

        ObjectUtil.unlockIdentity(context, identity);

        try{
          if(null!=identity ){

            String activeAdLink=null;
            ProvisioningPlan plan = new ProvisioningPlan();

            linksAccount=(List) identity.getLinks();
            identity.setProtected(false);
            identity.setAttribute("personaType","");
            context.saveObject(identity);
            context.commitTransaction();
            linksDelIterator = linksAccount.iterator();
            while(linksDelIterator.hasNext()){

              Link accounts = (Link) linksDelIterator.next();

              String appName=accounts.getApplicationName();
              String appType =accounts.getApplication().getType(); 
              if(null != appName && null !=appType){ 

                if(appName.equalsIgnoreCase(applicationName)){

                  String user=accounts.getAttribute("EMPLID");
                  String loc=accounts.getAttribute("SETID_LOCATION");
                  String strType=accounts.getAttribute("PER_ORG");

                  if(user!=null && loc!=null && strType!=null){
                    if(strType.equalsIgnoreCase("CWR") && loc.equalsIgnoreCase("ILARL") ){	

                      username = accounts.getNativeIdentity();

                      AccountRequest acctReq = new AccountRequest();
                      acctReq.setApplication(applicationName);
                      acctReq.setNativeIdentity(username);
                      acctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Delete);

                      plan.add(acctReq);
                      plan.setIdentity(identity);

                    }
                  }
                }
              }

            }
            sailpoint.tools.Util.flushIterator(linksDelIterator);
            if(plan !=null){

              Provisioner delProv = new Provisioner(context);
              delProv.setNoLocking(true);
              delProv.setLocalUpdate(true);                    
              ProvisioningProject project = delProv.compile(plan);
              delProv.execute(plan);

            }
          }

        } catch (Exception e) {      
          throw e; 
        }
      }
    }
  }
